from elevenlabs.client import ElevenLabs from elevenlabs import stream
client = ElevenLabs()
def speak_streaming(text: str, voice_id: str = "JBFqnCBsd6RMkjVDRZzb") -> None: """Stream audio directly to speakers with minimal latency.""" audio_stream = client.text_to_speech.stream( voice_id=voice_id, text=text, model_id="eleven_flash_v2_5", output_format="mp3_44100_128", ) stream(audio_stream)

import re from typing import Generator
def split_into_chunks(text: str, max_sentences: int = 2) -> Generator[str, None, None]: """Split text at sentence boundaries for streaming TTS.""" sentence_pattern = re.compile(r'(?<=[.!?])\s+') sentences = sentence_pattern.split(text.strip())
buffer = [] for sentence in sentences: buffer.append(sentence) if len(buffer) >= max_sentences: yield ' '.join(buffer) buffer = [] if buffer: yield ' '.join(buffer)
